// ===== AGENT VGC (Champions) =====
const vroad=$('Victory Road').first().json.data;
let prev=null; try{ prev=$('Veille vgc').first().json; }catch(e){}
const strip=s=>String(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
const now=new Date(), iso=now.toISOString();
const seed=now.getDate()+now.getMonth()*31;
const news=[...String(vroad).matchAll(/<h[23][^>]*>([\s\S]*?)<\/h[23]>/g)].map(m=>strip(m[1]))
 .filter(t=>/won|Champion|results|NAIC|Regional|Championships|Challenge/i.test(t)).slice(0,6);
const prevNews=(prev&&prev.newsFeed)||[];
const fresh=news.filter(n=>!prevNews.includes(n));
const tp=(prev&&prev.topPokemon)||[];
const lead=tp[0]; const spot=tp.length?tp[(seed+3)%tp.length]:null;
const summary="Regulation Set M-A (Pokémon Champions)"+(lead?" — "+lead.name+" domine ("+(lead.usage||lead.usageRate)+"%)":"")+". "
 +(fresh[0]?"🆕 "+fresh[0].slice(0,110)+".":(news[0]?"Actu : "+news[0].slice(0,110)+".":""))
 +(spot&&spot!==lead?" Pokémon du jour : "+spot.name+" ("+(spot.usage||spot.usageRate)+"%).":"");
const out=Object.assign({},prev||{},{metaSummary:summary,newsFeed:news,updatedAt:iso});
return [{json:{content:JSON.stringify(out,null,2),msg:"bot(vgc) "+now.toLocaleDateString('fr-FR')+(fresh.length?" : "+fresh.length+" nouvelle(s) actu":" : RAS, rotation du zoom")}}];
